 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachineCondition } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import PendingChangesBreadcrumb from '@kubevirt-utils/components/PendingChanges/PendingChangesBreadcrumb/PendingChangesBreadcrumb';
 5	import { getPendingChangesByTab } from '@kubevirt-utils/components/PendingChanges/utils/helpers';
 6	import { PendingChange } from '@kubevirt-utils/components/PendingChanges/utils/types';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { List } from '@patternfly/react-core';
 9	
10	type RestartPendingChangesProps = {
11	  pendingChanges: PendingChange[];
12	  restartRequiredCondition?: V1VirtualMachineCondition;
13	};
14	
15	const RestartPendingChanges: FC<RestartPendingChangesProps> = ({
16	  pendingChanges,
17	  restartRequiredCondition,
18	}) => {
19	  const { t } = useKubevirtTranslation();
20	
21	  const pendingChangesTabs = getPendingChangesByTab(pendingChanges);
22	  const {
23	    pendingChangesDetailsTab,
24	    pendingChangesDisksTab,
25	    pendingChangesEnvTab,
26	    pendingChangesNICsTab,
27	    pendingChangesSchedulingTab,
28	    pendingChangesScriptsTab,
29	  } = pendingChangesTabs;
30	
31	  return (
32	    <span>
33	      {restartRequiredCondition?.message ||
34	        t(
35	          'The following areas have pending changes that will be applied when this VirtualMachine is restarted.',
36	        )}
37	
38	      <List>
39	        <PendingChangesBreadcrumb pendingChanges={pendingChangesDetailsTab} />
40	        <PendingChangesBreadcrumb pendingChanges={pendingChangesSchedulingTab} />
41	        <PendingChangesBreadcrumb pendingChanges={pendingChangesEnvTab} />
42	        <PendingChangesBreadcrumb pendingChanges={pendingChangesNICsTab} />
43	        <PendingChangesBreadcrumb pendingChanges={pendingChangesScriptsTab} />
44	        <PendingChangesBreadcrumb pendingChanges={pendingChangesDisksTab} />
45	      </List>
46	    </span>
47	  );
48	};
49	
50	export default RestartPendingChanges;

